export interface BDTrainStation {
  id: string;
  name: string;
  bnName: string;
  lat: number;
  lng: number;
}

export interface BDTrainFare {
  shuvan: number;
  shuvanChair: number;
  snigdha: number;
  firstClassBerth?: number;
  acBerth?: number;
}

export interface BDTrainRoute {
  id: string;
  name: string;
  bnName: string;
  number: string;
  type: 'Express' | 'Mail' | 'Intercity' | 'Local';
  from: string;
  to: string;
  stops: string[];
  dhakaDepart: string;
  destinationArrive: string;
  returnDepart: string;
  dhakaArrive: string;
  offDay: string;
  distanceKm: number;
  fare: BDTrainFare;
  color: string;
  division: string;
}

// ── Utility functions ─────────────────────────────────────────────────────────
export function routeDistanceBetween(route: BDTrainRoute, fromId: string, toId: string): number {
  const si = route.stops.indexOf(fromId);
  const ei = route.stops.indexOf(toId);
  if (si === -1 || ei === -1) return route.distanceKm;
  const totalStops = route.stops.length;
  const segStops = Math.abs(ei - si);
  return Math.round((segStops / Math.max(totalStops - 1, 1)) * route.distanceKm);
}

export function calcTrainFare(distanceKm: number): { shuvan: number; shuvanChair: number; snigdha: number; acBerth: number } {
  const shuvan = Math.max(80, Math.round(distanceKm * 1.12));
  return { shuvan, shuvanChair: Math.round(shuvan * 1.32), snigdha: Math.round(shuvan * 1.92), acBerth: Math.round(shuvan * 3.93) };
}

